<script setup lang="ts">
import { ref,computed } from 'vue'; import Dialog from 'primevue/dialog'; import Button from 'primevue/button'; import FileUpload from 'primevue/fileupload'; import DataTable from 'primevue/datatable'; import Column from 'primevue/column'; import Message from 'primevue/message'; import ProgressSpinner from 'primevue/progressspinner'; import Tag from 'primevue/tag'; import { postDraftWrMetricsApi } from '../../infrastructure/PostDraftWrMetricsApi'; import { getErrorMessage } from '../../application/useWrMetricManagement'; import type { CsvPreviewResult,CsvImportResult,CsvPreviewRow } from '../../domain/WrMetricTypes'
const props=defineProps<{modelValue:boolean}>(); const emit=defineEmits<{ 'update:modelValue':[boolean]; imported:[] }>(); const file=ref<File|null>(null), preview=ref<CsvPreviewResult|null>(null), result=ref<CsvImportResult|null>(null), loading=ref(false), error=ref('');
const sections=computed(()=>preview.value?[['Valid rows',preview.value.validRows],['Invalid rows',preview.value.invalidRows],['Missing prospects',preview.value.missingProspects],['Duplicates',preview.value.duplicates],['Existing updates',preview.value.updates],['Verified overwrite protection',preview.value.protectedVerifiedRecords],['Skipped rows',preview.value.skippedRows]].filter((x):x is [string,CsvPreviewRow[]]=>Array.isArray(x[1])&&x[1].length>0):[])
function selected(e:{files:File[]}){file.value=e.files[0]??null;preview.value=null;result.value=null} async function runPreview(){if(!file.value)return;loading.value=true;error.value='';try{preview.value=await postDraftWrMetricsApi.previewCsv(file.value)}catch(e:unknown){error.value=getErrorMessage(e)}finally{loading.value=false}} async function runImport(){if(!file.value||!preview.value)return;loading.value=true;error.value='';try{result.value=await postDraftWrMetricsApi.importCsv(file.value);emit('imported')}catch(e:unknown){error.value=getErrorMessage(e)}finally{loading.value=false}}
</script><template><Dialog :visible="modelValue" modal header="Import WR Metrics from CSV" :style="{width:'min(72rem,96vw)'}" @update:visible="emit('update:modelValue',$event)"><Message v-if="error" severity="error" :closable="false">{{error}}</Message><FileUpload mode="basic" accept=".csv,text/csv" chooseLabel="Select CSV" :customUpload="true" @select="selected"/><Button label="Preview Upload" icon="pi pi-search" :disabled="!file" :loading="loading" @click="runPreview"/><ProgressSpinner v-if="loading"/><div v-if="preview"><div class="summary"><Tag v-for="(value,key) in preview.summary" :key="key" :value="`${key}: ${value}`" /></div><section v-for="section in sections" :key="section[0]"><h3>{{section[0]}}</h3><DataTable :value="section[1]" scrollable scrollHeight="18rem"><Column field="rowNumber" header="Row"/><Column field="prospectId" header="Prospect"/><Column field="action" header="Action"/><Column header="Errors"><template #body="{data}">{{data.errors?.join('; ')}}</template></Column><Column header="Warnings"><template #body="{data}">{{data.warnings?.join('; ')}}</template></Column></DataTable></section><Button label="Confirm Import" icon="pi pi-upload" severity="success" :loading="loading" @click="runImport"/></div><Message v-if="result" severity="success" :closable="false">Import completed. Imported {{result.imported??0}}, updated {{result.updated??0}}, skipped {{result.skipped??0}}, failed {{result.failed??0}}.</Message></Dialog></template><style scoped>.summary{display:flex;gap:.5rem;flex-wrap:wrap;margin:1rem 0}section{margin-top:1rem}</style>
